function x589001_ProcEnumEvent(varMap, varPlayer, varTalknpc, varQuest)
	
	TalkAppendButton(varMap, x589001_var_FileId, x589001_var_MissionName, 3)

end

function x589001_ProcEventEntry( varMap, varPlayer, varTalknpc, varQuest)
	StartTalkTask(varMap)	
	TalkAppendString(varMap,x589001_var_MissionText)		
	StopTalkTask()	
	DeliverTalkInfo(varMap, varPlayer, varTalknpc, x589001_var_FileId, -1)
end

function x589001_ProcAcceptCheck(varMap, varPlayer, varTalknpc)
	local minOfDay = GetMinOfDay()
	local weekIdx = GetWeek()
	if minOfDay > 480 and minOfDay < 1380 then
		ChangeMapRestrictiveMode(varMap, -1)--Йи
		return
	end
	local varX,z = x589001_GetScencePosition(varMap, varPlayer, npos)
	NewWorld(varMap, varPlayer, 545, varX, z, x589001_var_FileId)
end

function x589001_EnterScene( varMap, varPlayer)
	local minOfDay = GetMinOfDay()
	local weekIdx = GetWeek()
	
	if varMap ~= 545 then
		x589001_DelScencePlayerBuff(varMap)
		return
	end
	if weekIdx~=0 and weekIdx~=1 and weekIdx~=2 and weekIdx~=3 and weekIdx~=4 and weekIdx~=5 and weekIdx~=6 then
		return
	end
	if minOfDay < 480 or minOfDay > 1380 then --аЁгк--Дѓгк
		ChangeMapRestrictiveMode(varMap, -1)--Йи
		NewWorld(varMap, varPlayer, 0, varX, z, x589001_var_FileId)
		x589001_DelScencePlayerBuff(varMap)
		return
	end

end

function x589001_LeaveScence( varMap, varPlayer)
	if varMap ~= 545 then
		for i, item in x589001_var_PlayerBuff do
			DispelSpecificImpact(varMap, varPlayer, item.buffid, 1)
		end
	end
end

function x589001_GetScenceDrop(varMap, varPlayer, npos)
	--ГЁОАЫцЛњИДЛю
	local npos = random(1,56)
	local x1 = x589001_var_ReliveDrop[npos].varX
	local z1 = x589001_var_ReliveDrop[npos].z
	return x1,z1
	
end

function x589001_GetScencePosition(varMap, varPlayer, npos)
	--НјШызјБъ
	local npos = random(1,10)
	local x1 = x589001_var_EnterScence[npos].varX
	local z1 = x589001_var_EnterScence[npos].z
	return x1,z1
	
end


function x589001_GetLeaveScencePosition(varMap, varPlayer, npos)
	--ЬпШЫзјБъ
	local x1 = x589001_var_LeaveScence.varX
	local z1 = x589001_var_LeaveScence.z
	return x1,z1	
end

function x589001_ProcPlayerDie(varMap, varPlayer, varKiller)
	
	local nKillerType = GetObjType(varMap, varKiller)
	
	--ЕБЩБШЫепЮЊЙжЮядђЗЕЛи
	if nKillerType == 2 then
		return
	end
	
	if nKillerType == 3 then
		varKiller = GetOwnerID(varMap, varKiller)
	end	
	
	local minOfDay = GetMinOfDay()
	local weekIdx = GetWeek()	
	local teamid = GetTeamId(varMap, varKiller)
	local teamnum = GetNearTeamCount(varMap, varKiller)

	--ЛїЩБЭцМв
	if varMap ~= 545 then
		return
	end
	
	if weekIdx~=0 and weekIdx~=1 and weekIdx~=2 and weekIdx~=3 and weekIdx~=4 and weekIdx~=5 and weekIdx~=6 then
		return
	end
	
	if minOfDay < 480 or minOfDay > 1380 then--аЁгкДѓгк
		return
	end
	
	--if x589001_GetSelfBuffid(varMap, varKiller) == 0 then
		--SendSpecificImpactToUnit(varMap, varKiller, varKiller, varKiller, 30549, 0)
		--return
	--end
	
	local nBeKilled = GetPlayerRuntimeData(varMap,varKiller,RD_KING_BATTLE_BEKILLED ) + 1
	if nBeKilled > 10 then
		Msg2Player(varMap, varKiller,format("вбЭъГЩНБРјДЮЪ§ЮоЗЈдй#GЛёЕУ#OЯжН№НБРј %d", nBeKilled),8, 2)
		Msg2Player(varMap, varKiller,format("вбЭъГЩНБРјДЮЪ§ЮоЗЈдй#GЛёЕУ#OЯжН№НБРј %d", nBeKilled),8, 3)
		return
	end
		if teamid == -1 then
			AddGold(varMap, varKiller,x589001_var_nMoney2)
			Msg2Player(varMap, varKiller,format("Фудк#RДѓТвЖЗжа#OЩБЫРЭцМв#GЛёЕУ%dЮФ#OЯжН№ %d", x589001_var_nMoney2, nBeKilled),8, 2)
			Msg2Player(varMap, varKiller,format("Фудк#RДѓТвЖЗжа#OЩБЫРЭцМв#GЛёЕУ%dЮФ#OЯжН№ %d", x589001_var_nMoney2, nBeKilled),8, 3)
		else
			for varI = 0, teamnum - 1 do
				local memberId = GetNearTeamMember(varMap, varKiller, varI)
				if GetHp(varMap, memberId) > 0 then
				AddGold(varMap, varKiller,x589001_var_nMoney2)
				Msg2Player(varMap, varKiller,format("Фудк#RДѓТвЖЗжа#OЩБЫРЭцМв#GЛёЕУ%dЮФ#OЯжН№ %d", x589001_var_nMoney2, nBeKilled),8, 2)
				Msg2Player(varMap, varKiller,format("Фудк#RДѓТвЖЗжа#OЩБЫРЭцМв#GЛёЕУ%dЮФ#OЯжН№ %d", x589001_var_nMoney2, nBeKilled),8, 3)
				end
			end
		end
	SetPlayerRuntimeData(varMap,varKiller,RD_KING_BATTLE_BEKILLED,nBeKilled)	
end


function x589001_GetSelfBuffid(varMap, varPlayer)
	for i, item in x589001_var_PlayerBuff do
		if IsHaveSpecificImpact(varMap, varPlayer, item.buffid) == 1 then
			return item.buffcount
		end
	end	
	return 0
end


