	    Msg2Player(varMap, varPlayer,format("Фудк#RДѓТвЖЗжа#OБЛЛїЩБжЛФм#GЛёЕУ%dЮФЯжН№ %d", x589001_var_nMoney1, nBeKilled),8, 3)
    end

    if nBeKilled == 10 then
		local varX,z = x589001_GetLeaveScencePosition(varMap, varPlayer, npos)
		local varStr = format("#RЁОЭцМвЁП#G%s#oдк#RДѓТвЖЗГЁОА#oжаЫРЭіДЮЪ§вбТњБЛЦШРыПЊеНГЁЁЃ",GetName(varMap,varPlayer ))
