function x589001_ProcTimerDoingStart( varMap, varAct, varParam1, varParam2, varParam3, varParam4, Param5 )

	local minOfDay = GetMinOfDay()
	local weekIdx = GetWeek()
	if varMap ~= 545 then
		return
	end
	if weekIdx~=0 and weekIdx~=1 and weekIdx~=2 and weekIdx~=3 and weekIdx~=4 and weekIdx~=5 and weekIdx~=6 then
		return
	end
	if minOfDay < 480 or minOfDay > 1380 then--аЁгкДѓгк

		return
	end
	
	x589001_GetScencePlayerState(varMap) 
	ChangeMapRestrictiveMode(varMap, 2)--ПЊ
	SetSystemTimerTick( varMap, x589001_var_FileId, "ProcTimerTick", varAct, 1000)
end



