function x589001_GetScencePlayerState(varMap)
	local humanCount = GetScenePlayerCount(varMap)	
	for	i = 0, humanCount - 1 do
		local humanId = GetScenePlayerObjId(varMap, i)
		local haveImpact = IsHaveSpecificImpact(varMap, humanId, 7629)
		if(haveImpact > 0) then
			CancelSpecificImpact(varMap, humanId, 7629)
			StartTalkTask(varMap)
			TalkAppendString(varMap, "ДѓТвЖЗЛЅЩБЛюЖЏПЊЪМСЫЃЌеНГЕМгЛЄзДЬЌЯћЪЇ")
			StopTalkTask()
			DeliverTalkTips(varMap, humanId)
		end			
		SendSpecificImpactToUnit(varMap, humanId, humanId, humanId, 30549, 0)
	end
end

function x589001_DelScencePlayerBuff(varMap)
	local humanCount = GetScenePlayerCount(varMap)
	for	i = 0, humanCount - 1 do
		local humanId = GetScenePlayerObjId(varMap, i)
		for i, item in x589001_var_PlayerBuff do
			DispelSpecificImpact(varMap, humanId, item.buffid, 1)
		end	
	end		
end